args.sparql:
SELECT ?driver ?driverLabel WHERE {
  ?constructor wdt:P31 wd:Q3132075;
  wdt:P577 ?inception;
  wdt:P576 ?dissolution.
  FILTER(?inception <= "1986-01-01"^^xsd:gYear)
  FILTER(?dissolution >= "1991-01-01"^^xsd:gYear)

  ?driver wdt:P31 wd:Q5157005;
  wdt:P27 wd:Q145;
  wdt:P126 ?constructor;
  wdt:P569 ?birth.

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
ORDER BY DESC(?birth)
LIMIT 1

